<template>
  <v-container fluid>
    <v-btn color="blue lighten-3"
       to="/events"
       v-text="$t ('back_to.list')" />
    <v-btn color="blue lighten-3"
       @click="createDistance ()"
       v-text="$t ('distance.create')" />
    <v-layout column wrap>
      <v-tabs
        slider-color="blue"
        centered
        v-model="chosen_tab"
      >
        <v-tab :href="`#detail`">
          {{ $t ('contest.detail') }}
        </v-tab>
        <v-tab :href="`#distances`">
          {{ $t ('contest.distances') }}
        </v-tab>
      </v-tabs>
      <v-tabs-items v-model="chosen_tab">
        <v-tab-item :value="`detail`">
          <v-form
            ref="form"
            v-model="valid"
            class="profile ma-3"
            lazy-validation
          >
            <v-text-field
              v-model="form.name"
              :counter="100"
              :rules="nameRules"
              :label="$t ('contest_name')"
              required
            ></v-text-field>

            <v-text-field
              v-model="form.english_name"
              :counter="100"
              :label="$t ('contest_english_name')"
            ></v-text-field>

            <v-text-field
              v-model="form.organizer"
              :counter="100"
              :rules="nameRules"
              :label="$t ('organizer')"
              required
            ></v-text-field>

            <v-text-field
              v-model="form.english_organizer"
              :counter="100"
              :label="$t ('english_organizer')"
            ></v-text-field>

            <v-text-field
              v-model="form.location"
              :counter="100"
              :rules="nameRules"
              :label="$t ('location')"
              required
            ></v-text-field>

            <v-text-field
              v-model="form.english_location"
              :counter="100"
              :label="$t ('english_location')"
            ></v-text-field>

            <v-text-field
              v-model="form.region"
              :counter="100"
              :rules="nameRules"
              :label="$t ('region')"
              required
            ></v-text-field>

            <v-text-field
              v-model="form.url"
              :counter="200"
              :rules="urlRules"
              :label="$t ('link')"
              required
            ></v-text-field>

            <v-datetime-picker
              :label="$t ('start_at')"
              locale="zh-tw"
              v-model="form.start_at">
            </v-datetime-picker>

            <v-datetime-picker
              :label="$t ('sign_start_at')"
              locale="zh-tw"
              v-model="form.sign_start_at">
            </v-datetime-picker>

            <v-datetime-picker
              :label="$t ('sign_end_at')"
              locale="zh-tw"
              v-model="form.sign_end_at">
            </v-datetime-picker>

            <v-checkbox
              v-model="form.iaaf"
              :label="$t ('iaaf')"
            ></v-checkbox>

            <v-checkbox
              v-model="form.aims"
              :label="$t ('aims')"
            ></v-checkbox>
            
            <v-checkbox
              v-model="form.measured"
              :label="$t ('measured')"
            ></v-checkbox>

            <v-checkbox
              v-model="form.recordable"
              :label="$t ('recordable')"
            ></v-checkbox>

            <v-btn
              :disabled="!valid"
              color="blue lighten-3"
              @click="validate"
            >
              {{ $t ('submit') }}
            </v-btn>
          </v-form>
        </v-tab-item>
        <v-tab-item :value="`distances`">
          <v-list three-line>
            <v-list-tile
              v-for="(distance, index) in distances"
              @click="updateDistance (distance.id)"
              :key="index">
              <v-list-tile-content>
                <v-list-tile-title v-html="distance.name"></v-list-tile-title>
                <v-list-tile-sub-title v-html="distance.distance"></v-list-tile-sub-title>
                <v-list-tile-title v-html="distance.cost"></v-list-tile-title>
              </v-list-tile-content>
            </v-list-tile>
          </v-list>
        </v-tab-item>
      </v-tabs-items>
    </v-layout>
  </v-container>
</template>

<script>
export default {
  name: 'EventUpdate',
  data () {
    return {
      valid: false,
      id: null,
      chosen_tab: 'detail',
      distances: [],
      form: {
        name: '',
        english_name: '',
        organizer: '',
        english_organizer: '',
        location: '',
        english_location: '',
        level: '',
        region: '',
        url: '',
        start_at: null,
        sign_start_at: null,
        sign_end_at: null,
        iaaf: false,
        aims: false,
        measured: false,
        recordable: false,
      },
      nameRules: [
        v => !!v || 'Name is required',
        v => (v && v.length <= 100) || 'Name must be less than 100 characters'
      ],
      urlRules: [
        v => !!v || 'Url is required',
        v => (v && v.length <= 200) || 'Url must be less than 100 characters'
      ],
    }
  },
  created () {
    if ( ! this.hasPermission (true)) {
      this.$router.replace ('/events/index')
    }
    this.id = this.$route.params.id
    this.runnersPlaza.getEvent (this.id).then (event => {
      this.form = event
    })
    this.runnersPlaza.getDistances (this.id).then (distances => {
      this.distances = distances
    })
  },
  methods: {
    submit () {
      this.runnersPlaza.patchEvent (this.id, this.form).then ((event) => {
        this.form = event
      })
    },
    validate () {
      if (this.$refs.form.validate()) {
	this.submit()
      }
    },
    reset () {
      this.$refs.form.reset()
    },
    resetValidation () {
      this.$refs.form.resetValidation()
    },
    createDistance () {
      this.$router.replace ('/events/' + this.id + '/distances/create')
    },
    updateDistance (id) {
      this.$router.replace ('/events/' + this.id + '/distances/' + id + '/update')
    },
  },
}
</script>
